/**
 * @module ui/editorui/editoruiview
 */
import { View } from '@ckeditor/ckeditor5-ui/dist/view.js';
import { BodyCollection } from '@ckeditor/ckeditor5-ui/dist/editorui/bodycollection.js';
import { type EditableUIView } from '@ckeditor/ckeditor5-ui/dist/editableui/editableuiview.js';
import type { Locale, LocaleTranslate } from '@ckeditor/ckeditor5-utils';
import '../../theme/components/editorui/editorui.css';
import { type MenuBarView } from '@ckeditor/ckeditor5-ui/dist/menubar/menubarview.js';
import { type ToolbarView } from '@ckeditor/ckeditor5-ui/dist/toolbar/toolbarview.js';
/**
 * The editor UI view class. Base class for the editor main views.
 */
export declare abstract class EditorUIView extends View {
    /**
     * Collection of the child views, detached from the DOM
     * structure of the editor, like panels, icons etc.
     */
    readonly body: BodyCollection;
    locale: Locale;
    t: LocaleTranslate;
    abstract get editable(): EditableUIView;
    /**
     * Menu bar view instance. Initialized by default in:
     *
     * * balloon editor;
     * * decoupled editor;
     * * multiroot editor.
     */
    menuBarView?: MenuBarView;
    /**
     * Toolbar view instance. Initialized by default in:
     *
     * * classic editor;
     * * decoupled editor;
     * * inline editor;
     * * multiroot editor.
     */
    toolbar?: ToolbarView;
    /**
     * Creates an instance of the editor UI view class.
     *
     * @param locale The locale instance.
     */
    constructor(locale: Locale);
    /**
     * @inheritDoc
     */
    render(): void;
    /**
     * @inheritDoc
     */
    destroy(): void;
}
